1:/**
2: * The Spider — public types.
3: *
4: * Rig and engine data model, CrawlResult, SpiderApi, and configuration.
5: * Engine yield shapes (DraftYields, SealYields) live here too so downstream
6: * packages can import them without depending on the engine implementation files.
7: */
9:import type { ZodSchema } from 'zod';
11:// ── Engine instance status ────────────────────────────────────────────
13:export type EngineStatus = 'pending' | 'running' | 'completed' | 'failed' | 'cancelled' | 'blocked';
15:// ── Block record ──────────────────────────────────────────────────────
17:/**
18: * Persisted record of an active engine block.
19: * Present on an EngineInstance when status === 'blocked'.
20: * Cleared when the block is resolved.
21: */
22:export interface BlockRecord {
23:  /** Block type identifier (matches a registered BlockType.id). */
24:  type: string;
25:  /** Structured condition payload — shape validated by the block type's conditionSchema. */
26:  condition: unknown;
27:  /** ISO timestamp when the engine was blocked. */
28:  blockedAt: string;
29:  /** Optional human-readable message from the engine. */
30:  message?: string;
31:  /** ISO timestamp of the last checker evaluation. Updated on every check cycle. */
32:  lastCheckedAt?: string;
33:}
35:// ── Engine instance ───────────────────────────────────────────────────
37:/**
38: * A single engine slot within a rig.
39: *
40: * `id` is the engine's position identifier (e.g. 'draft', 'implement').
41: * For the static pipeline it matches `designId`.
42: *
43: * `givensSpec` holds literal values set at spawn time (writ, role, commands).
44: * The Spider assembles `givens` from this directly; upstream yields arrive
45: * via `context.upstream` as the escape hatch.
46: */
47:export interface EngineInstance {
48:  /** Unique identifier within the rig (e.g. 'draft', 'implement'). */
49:  id: string;
50:  /** The engine design to look up in the Fabricator. */
51:  designId: string;
52:  /** Current execution status. */
53:  status: EngineStatus;
54:  /** Engine IDs that must be completed before this engine can run. */
55:  upstream: string[];
56:  /** Literal givens values set at rig spawn time. */
57:  givensSpec: Record<string, unknown>;
58:  /** Yields from a completed engine run (JSON-serializable). */
59:  yields?: unknown;
60:  /** Error message if this engine failed. */
61:  error?: string;
62:  /** Session ID from a launched quick engine, used by the collect step. */
63:  sessionId?: string;
64:  /** ISO timestamp when execution started. */
65:  startedAt?: string;
66:  /** ISO timestamp when execution completed (or failed). */
67:  completedAt?: string;
68:  /** Present when status === 'blocked'. Cleared when the block is resolved. */
69:  block?: BlockRecord;
70:}
72:// ── Rig ──────────────────────────────────────────────────────────────
74:export type RigStatus = 'running' | 'completed' | 'failed' | 'blocked';
76:/**
77: * A rig — the execution context for a single writ.
78: *
79: * Stored in The Stacks (`spider/rigs` book). The `engines` array is the
80: * ordered pipeline of engine instances. The Spider updates this document
81: * in-place as engines run and complete.
82: */
83:export interface RigDoc {
84:  /** Index signature required to satisfy BookEntry constraint. */
85:  [key: string]: unknown;
86:  /** Unique rig id. */
87:  id: string;
88:  /** The writ this rig is executing. */
89:  writId: string;
90:  /** Current rig status. */
91:  status: RigStatus;
92:  /** Ordered engine pipeline. */
93:  engines: EngineInstance[];
94:  /** ISO timestamp when the rig was created. */
95:  createdAt: string;
96:  /** Engine id whose yields provide the resolution summary. Set at spawn time. */
97:  resolutionEngineId?: string;
98:}
100:// ── Rig filters ───────────────────────────────────────────────────────
102:/**
103: * Filters for listing rigs.
104: */
105:export interface RigFilters {
106:  /** Filter by rig status. */
107:  status?: RigStatus;
108:  /** Maximum number of results (default: 20). */
109:  limit?: number;
110:  /** Number of results to skip. */
111:  offset?: number;
112:}
114:// ── Rig templates ─────────────────────────────────────────────────────
116:/**
117: * A single engine slot declared in a rig template.
118: */
119:export interface RigTemplateEngine {
120:  /** Engine id unique within this template. */
121:  id: string;
122:  /** Engine design id to look up in the Fabricator. */
123:  designId: string;
124:  /** Engine ids within this template whose completion is required first. Defaults to []. */
125:  upstream?: string[];
126:  /**
127:   * Givens to pass at spawn time.
128:   * String values starting with '$' (either $name or ${name}) are variable
129:   * references resolved at spawn time:
130:   *   '$writ' or '${writ}' — the WritDoc for this rig's writ
131:   *   '$vars.<key>' or '${vars.<key>}' — value from spider.variables config
132:   * Non-string values are passed through literally.
133:   * Variables that resolve to undefined cause the key to be omitted.
134:   */
135:  givens?: Record<string, unknown>;
136:}
138:/**
139: * A complete rig template.
140: */
141:export interface RigTemplate {
142:  /** Ordered list of engine slot declarations. */
143:  engines: RigTemplateEngine[];
144:  /**
145:   * Engine id whose yields provide the writ resolution summary.
146:   * Falls back to seal engine, then last completed engine in array order.
147:   */
148:  resolutionEngine?: string;
149:}
151:// ── CrawlResult ────────────────────────────────────────────────────────
153:/**
154: * The result of a single crawl() call.
155: *
156: * Variants, ordered by priority:
157: * - 'engine-completed'  — an engine finished (collected or ran inline); rig still running
158: * - 'engine-started'    — launched a quick engine's session
159: * - 'engine-blocked'    — engine entered blocked status; rig is still running (other engines active)
160: * - 'engine-unblocked'  — a blocked engine's condition cleared; engine returned to pending
161: * - 'rig-spawned'       — created a new rig for a ready writ
162: * - 'rig-completed'     — the crawl step caused a rig to reach a terminal state
163: * - 'rig-blocked'       — all forward progress stalled; rig entered blocked status
164: *
165: * null means no work was available.
166: */
167:export type CrawlResult =
168:  | { action: 'engine-completed'; rigId: string; engineId: string }
169:  | { action: 'engine-started'; rigId: string; engineId: string }
170:  | { action: 'engine-blocked'; rigId: string; engineId: string; blockType: string }
171:  | { action: 'engine-unblocked'; rigId: string; engineId: string }
172:  | { action: 'rig-spawned'; rigId: string; writId: string }
173:  | { action: 'rig-completed'; rigId: string; writId: string; outcome: 'completed' | 'failed' }
174:  | { action: 'rig-blocked'; rigId: string; writId: string };
176:// ── Block type ────────────────────────────────────────────────────────
178:/**
179: * A registered block type — defines how to check whether a blocking
180: * condition has cleared. Contributed via kit/supportKit `blockTypes`.
181: */
182:export interface BlockType {
183:  /** Unique identifier (e.g. 'writ-status', 'scheduled-time'). */
184:  id: string;
185:  /** Lightweight checker — returns true if the blocking condition has cleared. */
186:  check: (condition: unknown) => Promise<boolean>;
187:  /** Zod schema for validating the condition payload at block time. */
188:  conditionSchema: ZodSchema;
189:  /** Suggested poll interval in milliseconds. If absent, check every crawl cycle. */
190:  pollIntervalMs?: number;
191:}
193:// ── SpiderApi ─────────────────────────────────────────────────────────
195:/**
196: * The Spider's public API — retrieved via guild().apparatus<SpiderApi>('spider').
197: */
198:export interface SpiderApi {
199:  /**
200:   * Execute one step of the crawl loop.
201:   *
202:   * Priority ordering: collect > checkBlocked > run > spawn.
203:   * Returns null when no work is available.
204:   */
205:  crawl(): Promise<CrawlResult | null>;
207:  /**
208:   * Show a rig by id. Throws if not found.
209:   */
210:  show(id: string): Promise<RigDoc>;
212:  /**
213:   * List rigs with optional filters, ordered by createdAt descending.
214:   */
215:  list(filters?: RigFilters): Promise<RigDoc[]>;
217:  /**
218:   * Find the rig for a given writ. Returns null if no rig exists.
219:   */
220:  forWrit(writId: string): Promise<RigDoc | null>;
222:  /**
223:   * Manually clear a block on a specific engine, regardless of checker result.
224:   * Throws if the engine is not blocked.
225:   */
226:  resume(rigId: string, engineId: string): Promise<void>;
228:  /**
229:   * Look up a registered block type by ID.
230:   */
231:  getBlockType(id: string): BlockType | undefined;
232:}
234:// ── Configuration ─────────────────────────────────────────────────────
236:/**
237: * Spider apparatus configuration — lives under the `spider` key in guild.json.
238: */
239:export interface SpiderConfig {
240:  /**
241:   * Polling interval for crawlContinual tool (milliseconds).
242:   * Default: 5000.
243:   */
244:  pollIntervalMs?: number;
245:  /**
246:   * Build command to pass to quick engines.
247:   */
248:  buildCommand?: string;
249:  /**
250:   * Test command to pass to quick engines.
251:   */
252:  testCommand?: string;
253:  /**
254:   * Writ type → rig template mappings.
255:   * 'default' key is the fallback for unmatched writ types.
256:   * Spawning fails if no matching template is found.
257:   */
258:  rigTemplates?: Record<string, RigTemplate>;
259:  /**
260:   * User-defined variables available in rig template givens via '$vars.<key>'.
261:   * Values are passed through literally (string, number, boolean).
262:   * Variables resolving to undefined (key absent) cause the givens key to be omitted.
263:   */
264:  variables?: Record<string, unknown>;
265:}
267:// ── Engine yield shapes ───────────────────────────────────────────────
269:/**
270: * Yields from the `draft` clockwork engine.
271: * The Spider stores these in the engine instance and passes them
272: * to downstream engines via context.upstream['draft'].
273: */
274:export interface DraftYields {
275:  /** The draft's unique id. */
276:  draftId: string;
277:  /** Codex this draft belongs to. */
278:  codexName: string;
279:  /** Git branch name for the draft. */
280:  branch: string;
281:  /** Absolute filesystem path to the draft's worktree. */
282:  path: string;
283:  /** HEAD commit SHA at the time the draft was opened. Used by review engine to compute diffs. */
284:  baseSha: string;
285:}
287:/**
288: * Yields from the `seal` clockwork engine.
289: */
290:export interface SealYields {
291:  /** The commit SHA at head of the target branch after sealing. */
292:  sealedCommit: string;
293:  /** Git strategy used. */
294:  strategy: 'fast-forward' | 'rebase';
295:  /** Number of retry attempts. */
296:  retries: number;
297:  /** Number of inscriptions (commits) sealed. */
298:  inscriptionsSealed: number;
299:}
301:/**
302: * Yields from the `implement` quick engine.
303: * Set by the Spider's collect step when the Animator session completes.
304: */
305:export interface ImplementYields {
306:  /** The Animator session id. */
307:  sessionId: string;
308:  /** Terminal status of the session. */
309:  sessionStatus: 'completed' | 'failed';
310:}
312:/**
313: * A single mechanical check (build or test) run by the review engine
314: * before launching the reviewer session.
315: */
316:export interface MechanicalCheck {
317:  /** Check name. */
318:  name: 'build' | 'test';
319:  /** Whether the command exited with code 0. */
320:  passed: boolean;
321:  /** Combined stdout+stderr, truncated to 4KB. */
322:  output: string;
323:  /** Wall-clock duration of the check in milliseconds. */
324:  durationMs: number;
325:}
327:/**
328: * Yields from the `review` quick engine.
329: * Assembled by the Spider's collect step from session.output and session.metadata.
330: */
331:export interface ReviewYields {
332:  /** The Animator session id. */
333:  sessionId: string;
334:  /** Reviewer's overall assessment — true if the review passed. */
335:  passed: boolean;
336:  /** Structured markdown findings from the reviewer's final message. */
337:  findings: string;
338:  /** Mechanical check results run before the reviewer session. */
339:  mechanicalChecks: MechanicalCheck[];
340:}
342:/**
343: * Yields from the `revise` quick engine.
344: * Set by the Spider's collect step when the Animator session completes.
345: */
346:export interface ReviseYields {
347:  /** The Animator session id. */
348:  sessionId: string;
349:  /** Terminal status of the session. */
350:  sessionStatus: 'completed' | 'failed';
351:}
353:// Augment GuildConfig so `guild().guildConfig().spider` is typed.
354:declare module '@shardworks/nexus-core' {
355:  interface GuildConfig {
356:    spider?: SpiderConfig;
357:  }
358:}

