128:/**
129: * Normalize a variable reference by stripping optional curly braces.
130: * '${foo}' → '$foo', '$foo' → '$foo' (unchanged).
131: * Called before matching against known variable patterns.
132: */
133:function normalizeVarRef(value: string): string {
134:  if (value.startsWith('${') && value.endsWith('}')) {
135:    return '$' + value.slice(2, -1);
136:  }
137:  return value;
138:}
140:/**
141: * Look up the rig template for a given writ type.
142: * Falls back to 'default' template if no exact match.
143: * Throws if no matching template is found.
144: */
145:function lookupTemplate(writType: string, config: SpiderConfig): RigTemplate {
146:  const templates = config.rigTemplates;
147:  if (templates) {
148:    if (writType in templates) return templates[writType];
149:    if ('default' in templates) return templates['default'];
150:  }
151:  throw new Error(
152:    `[spider] No rig template found for writ type "${writType}" and no "default" template configured.`
153:  );
154:}
156:/**
157: * Resolve a template engine's givens map using a variables context.
158: * '$writ' → WritDoc, '$vars.<key>' → spiderConfig.variables[key].
159: * Keys resolving to undefined are omitted from the output.
160: * Non-'$' prefixed values are passed through as literals.
161: */
162:function resolveGivens(
163:  givens: Record<string, unknown> | undefined,
164:  context: { writ: WritDoc; spiderConfig: SpiderConfig },
165:): Record<string, unknown> {
166:  const result: Record<string, unknown> = {};
167:  for (const [key, value] of Object.entries(givens ?? {})) {
168:    if (typeof value !== 'string' || !value.startsWith('$')) {
169:      result[key] = value;
170:    } else {
171:      const normalized = normalizeVarRef(value);
172:      if (normalized === '$writ') {
173:        result[key] = context.writ;
174:      } else if (/^\$vars\.[a-zA-Z_][a-zA-Z0-9_]*$/.test(normalized)) {
175:        const varKey = normalized.slice('$vars.'.length);
176:        const resolved = (context.spiderConfig.variables ?? {})[varKey];
177:        if (resolved !== undefined) {
178:          result[key] = resolved;
179:        }
180:        // undefined → omit key entirely
181:      }
182:      // Unrecognized $-prefixed strings are caught at validation time
183:    }
184:  }
185:  return result;
186:}
188:/**
189: * Build EngineInstance array and resolutionEngineId from a RigTemplate.
190: */
191:function buildFromTemplate(
192:  template: RigTemplate,
193:  context: { writ: WritDoc; spiderConfig: SpiderConfig },
194:): { engines: EngineInstance[]; resolutionEngineId?: string } {
195:  const engines: EngineInstance[] = template.engines.map((entry) => ({
196:    id: entry.id,
197:    designId: entry.designId,
198:    status: 'pending' as const,
199:    upstream: entry.upstream ?? [],
200:    givensSpec: resolveGivens(entry.givens, context),
201:  }));
202:  return { engines, resolutionEngineId: template.resolutionEngine };
203:}
205:/**
206: * Validate all configured rig templates at startup.
207: * Fails fast on the first error with a '[spider]' prefixed message.
208: */
209:function validateTemplates(
210:  rigTemplates: Record<string, RigTemplate>,
211:  fabricator: FabricatorApi,
212:): void {
213:  const builtinEngineIds = new Set([
214:    draftEngine.id,
215:    implementEngine.id,
216:    reviewEngine.id,
217:    reviseEngine.id,
218:    sealEngine.id,
219:  ]);
221:  for (const [templateKey, template] of Object.entries(rigTemplates)) {
222:    const engines = template.engines;
224:    // R13: Non-empty check
225:    if (engines.length === 0) {
226:      throw new Error(`[spider] rigTemplates.${templateKey}: template has no engines`);
227:    }
229:    // R6b: Duplicate ID check
230:    const engineIds = new Set<string>();
231:    for (const engine of engines) {
232:      if (engineIds.has(engine.id)) {
233:        throw new Error(
234:          `[spider] rigTemplates.${templateKey}: duplicate engine id "${engine.id}"`
235:        );
236:      }
237:      engineIds.add(engine.id);
238:    }
240:    // R6a: designId check
241:    for (const engine of engines) {
242:      const knownInFabricator = fabricator.getEngineDesign(engine.designId) !== undefined;
243:      const knownBuiltin = builtinEngineIds.has(engine.designId);
244:      if (!knownInFabricator && !knownBuiltin) {
245:        throw new Error(
246:          `[spider] rigTemplates.${templateKey}: engine "${engine.id}" references unknown designId "${engine.designId}"`
247:        );
248:      }
249:    }
251:    // R6c: Upstream reference check
252:    for (const engine of engines) {
253:      for (const upstreamId of engine.upstream ?? []) {
254:        if (!engineIds.has(upstreamId)) {
255:          throw new Error(
256:            `[spider] rigTemplates.${templateKey}: engine "${engine.id}" references unknown upstream "${upstreamId}"`
257:          );
258:        }
259:      }
260:    }
262:    // R6d: Cycle detection (DFS)
263:    {
264:      const visiting = new Set<string>();
265:      const visited = new Set<string>();
267:      const visit = (id: string): void => {
268:        if (visited.has(id)) return;
269:        if (visiting.has(id)) {
270:          throw new Error(
271:            `[spider] rigTemplates.${templateKey}: dependency cycle detected involving engine "${id}"`
272:          );
273:        }
274:        visiting.add(id);
275:        const engine = engines.find((e) => e.id === id)!;
276:        for (const dep of engine.upstream ?? []) {
277:          visit(dep);
278:        }
279:        visiting.delete(id);
280:        visited.add(id);
281:      };
283:      for (const engine of engines) {
284:        visit(engine.id);
285:      }
286:    }
288:    // R6e: resolutionEngine check
289:    if (template.resolutionEngine !== undefined && !engineIds.has(template.resolutionEngine)) {
290:      throw new Error(
291:        `[spider] rigTemplates.${templateKey}: resolutionEngine "${template.resolutionEngine}" is not an engine id in this template`
292:      );
293:    }
295:    // R7: Variable reference validation
296:    for (const engine of engines) {
297:      for (const value of Object.values(engine.givens ?? {})) {
298:        if (typeof value === 'string' && value.startsWith('$')) {
299:          const normalized = normalizeVarRef(value);
300:          if (
301:            normalized === '$writ' ||
302:            /^\$vars\.[a-zA-Z_][a-zA-Z0-9_]*$/.test(normalized)
303:          ) {
304:            continue; // valid
305:          }
306:          throw new Error(
307:            `[spider] rigTemplates.${templateKey}: engine "${engine.id}" has unrecognized variable "${value}"`
308:          );
309:        }
310:      }
311:    }
312:  }
313:}
