326:// ── Block type registry ────────────────────────────────────────────────
328:class BlockTypeRegistry {
329:  private readonly types = new Map<string, BlockType>();
331:  register(plugin: LoadedPlugin): void {
332:    if (isLoadedKit(plugin)) {
333:      this.registerFromKit(plugin.kit);
334:    } else if (isLoadedApparatus(plugin)) {
335:      if (plugin.apparatus.supportKit) {
336:        this.registerFromKit(plugin.apparatus.supportKit);
337:      }
338:    }
339:  }
341:  private registerFromKit(kit: Record<string, unknown>): void {
342:    const raw = kit.blockTypes;
343:    if (typeof raw !== 'object' || raw === null) return;
344:    for (const value of Object.values(raw as Record<string, unknown>)) {
345:      if (isBlockType(value)) {
346:        this.types.set(value.id, value);
347:      }
348:    }
349:  }
351:  get(id: string): BlockType | undefined {
352:    return this.types.get(id);
353:  }
354:}
