358:export function createSpider(): Plugin {
359:  let rigsBook: Book<RigDoc>;
360:  let sessionsBook: ReadOnlyBook<SessionDoc>;
361:  let writsBook: ReadOnlyBook<WritDoc>;
362:  let clerk: ClerkApi;
363:  let fabricator: FabricatorApi;
364:  let spiderConfig: SpiderConfig = {};
366:  const blockTypeRegistry = new BlockTypeRegistry();
368:  /**
369:   * In-memory store for block records that have been cleared.
370:   * Key: "rigId:engineId". Written when an engine is unblocked (via checker or resume()).
371:   * Read and deleted in tryRun() when building EngineRunContext.
372:   */
373:  const pendingPriorBlocks = new Map<string, BlockRecord>();
375:  // ── Internal crawl operations ─────────────────────────────────────
377:  /**
378:   * Mark an engine failed and propagate failure to the rig (same update).
379:   * Cancels all pending and blocked engines.
380:   */
381:  async function failEngine(
382:    rig: RigDoc,
383:    engineId: string,
384:    errorMessage: string,
385:  ): Promise<void> {
386:    const now = new Date().toISOString();
387:    const updatedEngines = rig.engines.map((e) => {
388:      if (e.id === engineId) {
389:        return { ...e, status: 'failed' as const, error: errorMessage, completedAt: now };
390:      }
391:      if (e.status === 'pending' || e.status === 'blocked') {
392:        return { ...e, status: 'cancelled' as const, block: undefined };
393:      }
394:      return e;
395:    });
396:    await rigsBook.patch(rig.id, {
397:      engines: updatedEngines,
398:      status: 'failed',
399:    });
400:  }
402:  /**
403:   * Phase 1 — collect.
404:   *
405:   * Find the first running engine with a sessionId whose session has
406:   * reached a terminal state. Populate yields and advance the engine
407:   * (and possibly the rig) to completed or failed.
408:   *
409:   * After collecting a completed engine, check whether the rig has
410:   * become blocked (no running engines, no runnable engines, some blocked).
411:   */
412:  async function tryCollect(): Promise<CrawlResult | null> {
413:    const runningRigs = await rigsBook.find({ where: [['status', '=', 'running']] });
414:    for (const rig of runningRigs) {
415:      for (const engine of rig.engines) {
416:        if (engine.status !== 'running' || !engine.sessionId) continue;
418:        const session = await sessionsBook.get(engine.sessionId);
419:        if (!session || session.status === 'running') continue;
421:        // Terminal session found — collect.
422:        const now = new Date().toISOString();
424:        if (session.status === 'failed' || session.status === 'timeout') {
425:          await failEngine(rig, engine.id, session.error ?? `Session ${session.status}`);
426:          return { action: 'rig-completed', rigId: rig.id, writId: rig.writId, outcome: 'failed' };
427:        }
429:        // Completed session — assemble yields via engine's collect() or generic default.
430:        const design = fabricator.getEngineDesign(engine.designId);
431:        let yields: unknown;
432:        if (design?.collect) {
433:          const givens = { ...engine.givensSpec };
434:          const upstream = buildUpstreamMap(rig);
435:          const context = { engineId: engine.id, upstream };
436:          yields = await design.collect(engine.sessionId!, givens, context);
437:        } else {
438:          yields = {
439:            sessionId: session.id,
440:            sessionStatus: session.status,
441:            ...(session.output !== undefined ? { output: session.output } : {}),
442:          };
443:        }
445:        if (!isJsonSerializable(yields)) {
446:          await failEngine(rig, engine.id, 'Session yields are not JSON-serializable');
447:          return { action: 'rig-completed', rigId: rig.id, writId: rig.writId, outcome: 'failed' };
448:        }
450:        const updatedEngines = rig.engines.map((e) =>
451:          e.id === engine.id
452:            ? { ...e, status: 'completed' as const, yields, completedAt: now }
453:            : e,
454:        );
456:        const allCompleted = updatedEngines.every((e) => e.status === 'completed');
458:        if (allCompleted) {
459:          await rigsBook.patch(rig.id, { engines: updatedEngines, status: 'completed' });
460:          return { action: 'rig-completed', rigId: rig.id, writId: rig.writId, outcome: 'completed' };
461:        }
463:        // Check whether completing this engine has caused the rig to become blocked
464:        if (isRigBlocked(updatedEngines)) {
465:          await rigsBook.patch(rig.id, { engines: updatedEngines, status: 'blocked' });
466:          return { action: 'rig-blocked', rigId: rig.id, writId: rig.writId };
467:        }
469:        await rigsBook.patch(rig.id, { engines: updatedEngines, status: 'running' });
470:        return { action: 'engine-completed', rigId: rig.id, engineId: engine.id };
471:      }
472:    }
473:    return null;
474:  }
476:  /**
477:   * Phase 2 — checkBlocked.
478:   *
479:   * Query rigs with status 'running' or 'blocked'. For each blocked engine,
480:   * run the registered checker (respecting pollIntervalMs). If cleared,
481:   * transition the engine back to pending and restore the rig to running.
482:   * If not cleared, update lastCheckedAt and continue to the next engine.
483:   */
484:  async function tryCheckBlocked(): Promise<CrawlResult | null> {
485:    // Fetch both running rigs (may have blocked engines) and blocked rigs
486:    const runningRigs = await rigsBook.find({ where: [['status', '=', 'running']] });
487:    const blockedRigs = await rigsBook.find({ where: [['status', '=', 'blocked']] });
488:    const rigs = [...runningRigs, ...blockedRigs];
490:    for (const rig of rigs) {
491:      for (const engine of rig.engines) {
492:        if (engine.status !== 'blocked' || !engine.block) continue;
494:        const blockType = blockTypeRegistry.get(engine.block.type);
495:        if (!blockType) continue; // Type was unregistered after block was created; skip
497:        // Poll interval throttle
498:        if (blockType.pollIntervalMs !== undefined && engine.block.lastCheckedAt) {
499:          const elapsed = Date.now() - new Date(engine.block.lastCheckedAt).getTime();
500:          if (elapsed < blockType.pollIntervalMs) continue;
501:        }
503:        let cleared: boolean;
504:        try {
505:          cleared = await blockType.check(engine.block.condition);
506:        } catch (err) {
507:          // Log warning, skip — engine stays blocked, retry next cycle
508:          console.warn(
509:            `Block checker "${engine.block.type}" threw for engine "${engine.id}" in rig "${rig.id}":`,
510:            err,
511:          );
512:          continue;
513:        }
515:        if (!cleared) {
516:          // Update lastCheckedAt and continue checking other engines
517:          const now = new Date().toISOString();
518:          const updatedEngines = rig.engines.map((e) =>
519:            e.id === engine.id
520:              ? { ...e, block: { ...e.block!, lastCheckedAt: now } }
521:              : e,
522:          );
523:          await rigsBook.patch(rig.id, { engines: updatedEngines });
524:          continue; // Check next engine
525:        }
527:        // Cleared — store block record in memory for priorBlock, then transition engine to pending
528:        const priorBlockRecord = engine.block;
529:        pendingPriorBlocks.set(`${rig.id}:${engine.id}`, priorBlockRecord);
531:        const updatedEngines = rig.engines.map((e) =>
532:          e.id === engine.id
533:            ? { ...e, status: 'pending' as const, block: undefined }
534:            : e,
535:        );
537:        // Restore rig to running if it was blocked; use isRigBlocked on updatedEngines
538:        // (always false after unblocking, but keeps call sites consistent per R13)
539:        const stillBlocked = isRigBlocked(updatedEngines);
540:        const rigStatus = stillBlocked ? 'blocked' : 'running';
542:        await rigsBook.patch(rig.id, {
543:          engines: updatedEngines,
544:          status: rigStatus,
545:        });
547:        return { action: 'engine-unblocked', rigId: rig.id, engineId: engine.id };
548:      }
549:    }
550:    return null;
551:  }
553:  /**
554:   * Phase 3 — run.
555:   *
556:   * Find the first pending engine in any running rig whose upstream is
557:   * all completed. Execute it:
558:   * - Clockwork ('completed') → store yields, mark engine completed,
559:   *   check for rig completion.
560:   * - Quick ('launched') → store sessionId, mark engine running.
561:   * - Blocked ('blocked') → validate block type and condition, persist
562:   *   block record, check whether rig should enter blocked state.
563:   */
564:  async function tryRun(): Promise<CrawlResult | null> {
565:    const runningRigs = await rigsBook.find({ where: [['status', '=', 'running']] });
566:    for (const rig of runningRigs) {
567:      const pending = findRunnableEngine(rig);
568:      if (!pending) continue;
570:      const design = fabricator.getEngineDesign(pending.designId);
571:      if (!design) {
572:        await failEngine(rig, pending.id, `No engine design found for "${pending.designId}"`);
573:        return { action: 'rig-completed', rigId: rig.id, writId: rig.writId, outcome: 'failed' };
574:      }
576:      const now = new Date().toISOString();
577:      const upstream = buildUpstreamMap(rig);
578:      const givens = { ...pending.givensSpec };
580:      // Check for a prior block record (engine was previously blocked and unblocked)
581:      const priorBlockKey = `${rig.id}:${pending.id}`;
582:      const priorBlock = pendingPriorBlocks.get(priorBlockKey);
583:      if (priorBlock) pendingPriorBlocks.delete(priorBlockKey);
585:      const context = {
586:        engineId: pending.id,
587:        upstream,
588:        ...(priorBlock ? { priorBlock } : {}),
589:      };
591:      let engineResult: Awaited<ReturnType<typeof design.run>>;
592:      try {
593:        // Mark engine as running before executing
594:        const startedEngines = rig.engines.map((e) =>
595:          e.id === pending.id ? { ...e, status: 'running' as const, startedAt: now } : e,
596:        );
597:        await rigsBook.patch(rig.id, { engines: startedEngines });
599:        // Re-fetch to get the up-to-date engines list (with startedAt set)
600:        const updatedRig = { ...rig, engines: startedEngines };
602:        engineResult = await design.run(givens, context);
604:        if (engineResult.status === 'launched') {
605:          // Quick engine — store sessionId, leave engine in 'running'
606:          const { sessionId } = engineResult;
607:          const launchedEngines = updatedRig.engines.map((e) =>
608:            e.id === pending.id
609:              ? { ...e, status: 'running' as const, sessionId }
610:              : e,
611:          );
612:          await rigsBook.patch(rig.id, { engines: launchedEngines });
613:          return { action: 'engine-started', rigId: rig.id, engineId: pending.id };
614:        }
616:        if (engineResult.status === 'blocked') {
617:          const { blockType: blockTypeId, condition, message } = engineResult;
619:          // Look up the block type
620:          const blockType = blockTypeRegistry.get(blockTypeId);
621:          if (!blockType) {
622:            await failEngine(updatedRig, pending.id, `Unknown block type: "${blockTypeId}"`);
623:            return { action: 'rig-completed', rigId: rig.id, writId: rig.writId, outcome: 'failed' };
624:          }
626:          // Validate the condition against the block type's schema
627:          try {
628:            blockType.conditionSchema.parse(condition);
629:          } catch (zodErr) {
630:            const zodMessage = zodErr instanceof Error ? zodErr.message : String(zodErr);
