637:          }
639:          // Build the block record and persist the blocked engine
640:          const blockRecord: BlockRecord = {
641:            type: blockTypeId,
642:            condition,
643:            blockedAt: new Date().toISOString(),
644:            ...(message !== undefined ? { message } : {}),
645:          };
647:          const blockedEngines = updatedRig.engines.map((e) =>
648:            e.id === pending.id
649:              ? { ...e, status: 'blocked' as const, block: blockRecord }
650:              : e,
651:          );
653:          // Determine whether the rig should also enter blocked state
654:          if (isRigBlocked(blockedEngines)) {
655:            await rigsBook.patch(rig.id, { engines: blockedEngines, status: 'blocked' });
656:            return { action: 'rig-blocked', rigId: rig.id, writId: rig.writId };
657:          }
659:          await rigsBook.patch(rig.id, { engines: blockedEngines });
660:          return { action: 'engine-blocked', rigId: rig.id, engineId: pending.id, blockType: blockTypeId };
661:        }
663:        // Clockwork engine — validate and store yields
664:        const { yields } = engineResult;
665:        if (!isJsonSerializable(yields)) {
666:          await failEngine(updatedRig, pending.id, 'Engine yields are not JSON-serializable');
