670:        const completedAt = new Date().toISOString();
671:        const completedEngines = updatedRig.engines.map((e) =>
672:          e.id === pending.id
673:            ? { ...e, status: 'completed' as const, yields, completedAt }
674:            : e,
675:        );
676:        const allCompleted = completedEngines.every((e) => e.status === 'completed');
677:        await rigsBook.patch(rig.id, {
678:          engines: completedEngines,
679:          status: allCompleted ? 'completed' : 'running',
680:        });
682:        if (allCompleted) {
683:          return { action: 'rig-completed', rigId: rig.id, writId: rig.writId, outcome: 'completed' };
684:        }
685:        return { action: 'engine-completed', rigId: rig.id, engineId: pending.id };
686:      } catch (err) {
