688:        await failEngine(rig, pending.id, errorMessage);
689:        return { action: 'rig-completed', rigId: rig.id, writId: rig.writId, outcome: 'failed' };
690:      }
691:    }
692:    return null;
693:  }
695:  /**
696:   * Phase 4 — spawn.
697:   *
698:   * Find the oldest ready writ with no existing rig. Create a rig and
699:   * transition the writ to active so the Clerk tracks it as in-progress.
700:   */
701:  async function trySpawn(): Promise<CrawlResult | null> {
702:    // Find ready writs ordered by creation time (oldest first)
703:    const readyWrits = await writsBook.find({
704:      where: [['status', '=', 'ready']],
705:      orderBy: ['createdAt', 'asc'],
706:      limit: 10,
707:    });
709:    for (const writ of readyWrits) {
710:      // Check for existing rig
711:      const existing = await rigsBook.find({
712:        where: [['writId', '=', writ.id]],
713:        limit: 1,
714:      });
715:      if (existing.length > 0) continue;
717:      const rigId = generateId('rig', 4);
718:      const template = lookupTemplate(writ.type, spiderConfig);
719:      const { engines, resolutionEngineId } = buildFromTemplate(template, {
720:        writ,
721:        spiderConfig,
722:      });
724:      const rig: RigDoc = {
725:        id: rigId,
726:        writId: writ.id,
727:        status: 'running',
728:        engines,
729:        createdAt: new Date().toISOString(),
730:        ...(resolutionEngineId !== undefined ? { resolutionEngineId } : {}),
731:      };
733:      await rigsBook.put(rig);
735:      // Transition writ to active so Clerk tracks it
736:      try {
737:        await clerk.transition(writ.id, 'active');
738:      } catch (err) {
739:        // Only swallow state-transition conflicts (writ already moved past 'ready')
740:        if (err instanceof Error && err.message.includes('transition')) {
741:          // Race condition — another spider got here first. The rig is already created,
742:          // so we continue. The writ is already active or beyond.
743:        } else {
744:          throw err;
745:        }
746:      }
748:      return { action: 'rig-spawned', rigId, writId: writ.id };
749:    }
751:    return null;
752:  }
754:  // ── SpiderApi ─────────────────────────────────────────────────────
756:  const api: SpiderApi = {
757:    async crawl(): Promise<CrawlResult | null> {
758:      const collected = await tryCollect();
759:      if (collected) return collected;
761:      const checked = await tryCheckBlocked();
762:      if (checked) return checked;
764:      const ran = await tryRun();
765:      if (ran) return ran;
767:      const spawned = await trySpawn();
768:      if (spawned) return spawned;
770:      return null;
771:    },
773:    async show(id: string): Promise<RigDoc> {
774:      const results = await rigsBook.find({ where: [['id', '=', id]], limit: 1 });
775:      if (results.length === 0) {
776:        throw new Error(`Rig "${id}" not found.`);
777:      }
778:      return results[0];
779:    },
781:    async list(filters?: RigFilters): Promise<RigDoc[]> {
782:      const where: WhereClause = [];
783:      if (filters?.status !== undefined) {
784:        where.push(['status', '=', filters.status]);
785:      }
786:      const limit = filters?.limit ?? 20;
787:      return rigsBook.find({
788:        where,
789:        orderBy: ['createdAt', 'desc'],
790:        limit,
791:        ...(filters?.offset !== undefined ? { offset: filters.offset } : {}),
792:      });
793:    },
795:    async forWrit(writId: string): Promise<RigDoc | null> {
796:      const results = await rigsBook.find({ where: [['writId', '=', writId]], limit: 1 });
797:      return results[0] ?? null;
798:    },
800:    async resume(rigId: string, engineId: string): Promise<void> {
801:      const rig = await api.show(rigId); // Throws if not found
802:      const engine = rig.engines.find((e) => e.id === engineId);
803:      if (!engine) {
804:        throw new Error(`Engine "${engineId}" not found in rig "${rigId}".`);
805:      }
806:      if (engine.status !== 'blocked') {
807:        throw new Error(
808:          `Engine "${engineId}" in rig "${rigId}" is not blocked (status: ${engine.status}).`,
809:        );
810:      }
812:      // Store prior block for priorBlock context on next run
813:      if (engine.block) {
814:        pendingPriorBlocks.set(`${rigId}:${engineId}`, engine.block);
815:      }
817:      const updatedEngines = rig.engines.map((e) =>
818:        e.id === engineId
819:          ? { ...e, status: 'pending' as const, block: undefined }
820:          : e,
821:      );
823:      const rigStatus = rig.status === 'blocked' ? 'running' : rig.status;
825:      await rigsBook.patch(rigId, {
826:        engines: updatedEngines,
827:        status: rigStatus,
828:      });
829:    },
831:    getBlockType(id: string): BlockType | undefined {
832:      return blockTypeRegistry.get(id);
833:    },
834:  };
836:  // ── Apparatus ─────────────────────────────────────────────────────
838:  return {
839:    apparatus: {
840:      requires: ['stacks', 'clerk', 'fabricator'],
841:      consumes: ['blockTypes'],
843:      supportKit: {
