845:          rigs: {
846:            indexes: ['status', 'writId', ['status', 'writId'], 'createdAt'],
847:          },
848:        },
849:        engines: {
850:          draft:     draftEngine,
851:          implement: implementEngine,
852:          review:    reviewEngine,
853:          revise:    reviseEngine,
854:          seal:      sealEngine,
855:        },
856:        blockTypes: {
857:          'writ-status':    writStatusBlockType,
858:          'scheduled-time': scheduledTimeBlockType,
859:          'book-updated':   bookUpdatedBlockType,
860:        },
861:        tools: [crawlOneTool, crawlContinualTool, rigShowTool, rigListTool, rigForWritTool, rigResumeTool],
