877:        }
879:        rigsBook = stacks.book<RigDoc>('spider', 'rigs');
880:        sessionsBook = stacks.readBook<SessionDoc>('animator', 'sessions');
881:        writsBook = stacks.readBook<WritDoc>('clerk', 'writs');
883:        // Scan all already-loaded kits for block types.
884:        // These fired plugin:initialized before any apparatus started.
885:        for (const kit of g.kits()) {
886:          blockTypeRegistry.register(kit);
887:        }
889:        // Subscribe to plugin:initialized for apparatus supportKits that
890:        // fire after us in the startup sequence.
891:        ctx.on('plugin:initialized', (plugin: unknown) => {
892:          const loaded = plugin as LoadedPlugin;
893:          if (isLoadedApparatus(loaded)) {
894:            blockTypeRegistry.register(loaded);
895:          }
896:        });
898:        // CDC — Phase 1 cascade on rigs book.
899:        // When a rig reaches a terminal state, transition the associated writ.
900:        // The 'blocked' status intentionally falls through — no CDC action.
901:        stacks.watch<RigDoc>(
902:          'spider',
903:          'rigs',
904:          async (event) => {
905:            if (event.type !== 'update') return;
907:            const rig = event.entry;
908:            const prev = event.prev;
910:            // Only act when status changes to a terminal state
911:            if (rig.status === prev.status) return;
913:            if (rig.status === 'completed') {
914:              let resolutionYields: unknown;
916:              // 1. Try the declared resolution engine
917:              if (rig.resolutionEngineId) {
918:                const declared = rig.engines.find((e) => e.id === rig.resolutionEngineId);
919:                if (declared?.yields !== undefined) {
920:                  resolutionYields = declared.yields;
921:                }
922:              }
924:              // 2. Fall back to seal engine (backwards compat for pre-existing rigs)
925:              if (resolutionYields === undefined) {
926:                const seal = rig.engines.find((e) => e.id === 'seal');
927:                if (seal?.yields !== undefined) {
928:                  resolutionYields = seal.yields;
929:                }
930:              }
932:              // 3. Fall back to last completed engine in array order
933:              if (resolutionYields === undefined) {
934:                const lastCompleted = [...rig.engines]
935:                  .reverse()
936:                  .find((e) => e.status === 'completed' && e.yields !== undefined);
937:                if (lastCompleted) {
938:                  resolutionYields = lastCompleted.yields;
939:                }
940:              }
942:              const resolution = resolutionYields !== undefined
943:                ? JSON.stringify(resolutionYields)
944:                : 'Rig completed';
945:              await clerk.transition(rig.writId, 'completed', { resolution });
946:            } else if (rig.status === 'failed') {
947:              const failedEngine = rig.engines.find((e) => e.status === 'failed');
948:              const resolution = failedEngine?.error ?? 'Engine failure';
949:              await clerk.transition(rig.writId, 'failed', { resolution });
950:            }
951:            // 'blocked' status — no CDC action, writ stays in current state
952:          },
953:          { failOnError: true },
954:        );
955:      },
956:    },
957:  };
958:}

