1:/**
2: * Built-in block type: writ-status.
3: *
4: * Blocks until a specific writ reaches a target status.
5: * Condition: { writId: string; targetStatus: string }
6: */
8:import { z } from 'zod';
9:import { guild } from '@shardworks/nexus-core';
10:import type { StacksApi } from '@shardworks/stacks-apparatus';
11:import type { WritDoc } from '@shardworks/clerk-apparatus';
12:import type { BlockType } from '../types.ts';
14:const conditionSchema = z.object({
15:  writId: z.string(),
16:  targetStatus: z.string(),
17:});
19:const writStatusBlockType: BlockType = {
20:  id: 'writ-status',
21:  conditionSchema,
22:  pollIntervalMs: 10_000,
23:  async check(condition: unknown): Promise<boolean> {
24:    const { writId, targetStatus } = conditionSchema.parse(condition);
25:    const stacks = guild().apparatus<StacksApi>('stacks');
26:    const writsBook = stacks.readBook<WritDoc>('clerk', 'writs');
27:    const results = await writsBook.find({ where: [['id', '=', writId]], limit: 1 });
28:    if (results.length === 0) return false;
29:    return results[0].status === targetStatus;
30:  },
31:};
33:export default writStatusBlockType;

