1:/**
2: * Built-in block type: book-updated.
3: *
4: * Blocks until a specific book (or document within it) has content.
5: * Condition: { ownerId: string; book: string; documentId?: string }
6: *
7: * When documentId is provided: checks if that specific document exists.
8: * When documentId is absent: checks if any document exists in the book.
9: */
11:import { z } from 'zod';
12:import { guild } from '@shardworks/nexus-core';
13:import type { StacksApi, BookEntry } from '@shardworks/stacks-apparatus';
14:import type { BlockType } from '../types.ts';
16:const conditionSchema = z.object({
17:  ownerId: z.string(),
18:  book: z.string(),
19:  documentId: z.string().optional(),
20:});
22:const bookUpdatedBlockType: BlockType = {
23:  id: 'book-updated',
24:  conditionSchema,
25:  pollIntervalMs: 10_000,
26:  async check(condition: unknown): Promise<boolean> {
27:    const { ownerId, book, documentId } = conditionSchema.parse(condition);
28:    const stacks = guild().apparatus<StacksApi>('stacks');
29:    const targetBook = stacks.readBook<BookEntry>(ownerId, book);
30:    if (documentId) {
31:      // Per-document: check if the document exists
32:      const doc = await targetBook.get(documentId);
33:      return doc !== null && doc !== undefined;
34:    }
35:    // Per-book: check if any documents exist
36:    const docs = await targetBook.find({ limit: 1 });
37:    return docs.length > 0;
38:  },
39:};
41:export default bookUpdatedBlockType;

